// ── STEP 1: INGEST with robust UUID ──
const raw = $json.body || $json || {};

function uuidV4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const sid = uuidRe.test(String(raw.session_id || '')) ? raw.session_id : uuidV4();
const directMsg = String(raw.message || '').trim();
const msgs = Array.isArray(raw.messages) ? raw.messages : [];

let userMessage = directMsg;
let assistantStart = '';
if (!userMessage) {
  for (const m of msgs) {
    if (m?.role === 'user' && Number(m?.turn) === 2) userMessage = String(m?.content || '');
    if (m?.role === 'assistant' && Number(m?.turn) === 1) assistantStart = String(m?.content || '');
  }
}
if (!userMessage) userMessage = 'Hello, I could use some support today.';
if (!assistantStart) assistantStart = "I'm here to listen and support you. How are you feeling today?";

const ctx = (raw.context && typeof raw.context === 'object') ? raw.context : {};
const turn = Number(raw.turn_index || 1);

return [{ json: {
  session_id: sid,
  turn_index: turn,
  clean_msg: userMessage,
  user_message: userMessage,
  assistant_start: assistantStart,
  evaluation_mode: Boolean(raw.evaluation_mode),
  api_request: Boolean(raw.api_request),
  context: { language: String(ctx.language || 'en'), canton: String(ctx.canton || 'ZH').slice(0,2) },
  conversation_context: `assistant: ${assistantStart}\nuser: ${userMessage}`,
  messages: msgs,
  ingested_at: new Date().toISOString()
}}];

// ── STEP 2: MERGE previous personality state (uses node references) ──
let ingestData = {};
try { ingestData = $('Enhanced Ingest (Zurich)').first().json; } catch(e) {}
if (!ingestData || !ingestData.session_id) {
  const all = $input.all();
  for (const item of all) {
    const j = item?.json;
    if (j && j.conversation_context !== undefined) { ingestData = j; break; }
  }
  if (!ingestData || !ingestData.session_id) ingestData = $input.first()?.json || {};
}

let dbRow = null;
try {
  const dbOut = $('Load Previous State (PostgreSQL)').first()?.json;
  if (dbOut && dbOut.ocean_o !== undefined) dbRow = dbOut;
} catch(e) {}
if (!dbRow) {
  for (const item of $input.all()) {
    const j = item?.json;
    if (j && j.ocean_o !== undefined) { dbRow = j; break; }
  }
}

let prevOcean = {O:0,C:0,E:0,A:0,N:0}, prevConf = {O:0.5,C:0.5,E:0.5,A:0.5,N:0.5};
let prevTurn = 0, prevStable = false, fromDb = false;
let prevHistory = [];
if (dbRow) {
  prevOcean = {O:dbRow.ocean_o||0, C:dbRow.ocean_c||0, E:dbRow.ocean_e||0, A:dbRow.ocean_a||0, N:dbRow.ocean_n||0};
  prevConf = {O:dbRow.confidence_o||0.5, C:dbRow.confidence_c||0.5, E:dbRow.confidence_e||0.5, A:dbRow.confidence_a||0.5, N:dbRow.confidence_n||0.5};
  prevTurn = dbRow.turn_index||0; prevStable = dbRow.stable||false; fromDb = true;
  prevHistory = Array.isArray(dbRow.ocean_history) ? dbRow.ocean_history : [];
}

return [{ json: {
  ...ingestData,
  previous_state: {
    ocean: prevOcean,
    confidence: prevConf,
    turn_index: prevTurn,
    stable: prevStable,
    ocean_history: prevHistory,
    loaded_from_db: fromDb
  }
}}];

// ── STEP 3: PERSONALITY DETECTION (fetch + heuristic fallback + EMA) ──
const d = $input.first().json;
const turnIndex = Number(d.turn_index || 1);
const userText = String(d.clean_msg || '').toLowerCase();
const convCtx = String(d.conversation_context || '');
const CONFIDENCE_THRESHOLD = 0.4;
const STABILITY_TURNS = 6;
const STABILITY_VARIANCE_THRESHOLD = 0.05;

function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

function heuristicOcean(text) {
  const pos = (text.match(/(good|calm|grateful|thank|appreciate|better|hopeful|peace|relaxed|happy|great|awesome|wonderful|fantastic|love|enjoy|excited)/g)||[]).length;
  const neg = (text.match(/(low|sad|anxious|worried|stress|overwhelmed|tired|panic|afraid|lonely|depressed|frustrated|angry|upset|hurt|scared|terrible|awful)/g)||[]).length;
  const soc = (text.match(/(you|we|together|friends|family|talk|share|people|connect|relationship)/g)||[]).length;
  const exp = (text.match(/(new|explore|learn|curious|idea|possibility|creative|wonder|imagine|discover)/g)||[]).length;
  const str = (text.match(/(plan|organize|routine|schedule|step|priority|focus|goal|structure)/g)||[]).length;
  const greet = (text.match(/(hi|hello|hey|how are you|good morning|good evening)/g)||[]).length;
  return {
    O: clamp(exp*0.15, -1, 1),
    C: clamp(str*0.14, -1, 1),
    E: clamp(soc*0.1 + pos*0.05 - neg*0.05 + greet*0.2, -1, 1),
    A: clamp(pos*0.08 + soc*0.05 + greet*0.1, -1, 1),
    N: clamp((neg-pos)*0.15, -1, 1)
  };
}

function oceanVariance(history) {
  if (!Array.isArray(history) || history.length < 2) return 0;
  const traits = ['O','C','E','A','N'];
  let sum = 0;
  for (const t of traits) {
    const values = history.map((h) => Number(h?.[t] || 0));
    const mean = values.reduce((a, b) => a + b, 0) / values.length;
    const variance = values.reduce((a, b) => a + ((b - mean) ** 2), 0) / values.length;
    sum += variance;
  }
  return sum / traits.length;
}

function applyEma(current, conf) {
  const alpha = 0.3;
  const prev = d.previous_state || {};
  const pO = prev.ocean || {O:0,C:0,E:0,A:0,N:0};
  const pC = prev.confidence || {O:0.5,C:0.5,E:0.5,A:0.5,N:0.5};
  const sO = {}, sC = {};
  ['O','C','E','A','N'].forEach(t => {
    const currTrait = Number(current[t] || 0);
    const currConf = Number(conf[t] || 0.5);
    const prevTrait = Number(pO[t] || 0);
    const prevConf = Number(pC[t] || 0.5);
    if (turnIndex === 1) {
      sO[t] = currTrait;
      sC[t] = currConf;
    } else if (currConf < CONFIDENCE_THRESHOLD) {
      sO[t] = prevTrait;
      sC[t] = alpha * currConf + (1 - alpha) * prevConf;
    } else {
      sO[t] = alpha * currTrait + (1 - alpha) * prevTrait;
      sC[t] = alpha * currConf + (1 - alpha) * prevConf;
    }
  });

  const prevHistory = Array.isArray(d.previous_state?.ocean_history) ? d.previous_state.ocean_history : [];
  const history = [...prevHistory, sO];
  const stable = history.length >= STABILITY_TURNS && oceanVariance(history.slice(-STABILITY_TURNS)) <= STABILITY_VARIANCE_THRESHOLD;

  return { smoothedOcean: sO, smoothedConfidence: sC, personalityStable: stable, oceanHistory: history.slice(-STABILITY_TURNS) };
}

let ocean, confidence, apiStatus = 'heuristic', apiError = null, formatUsed = 'heuristic-fallback';

try {
  const apiKey = process.env.NVIDIA_API_KEY || '';
  const apiUrl = process.env.NVIDIA_API_URL || 'https://integrate.api.nvidia.com/v1/chat/completions';
  const model = process.env.NVIDIA_MODEL || 'google/gemma-3-12b-it';

  if (apiKey && apiKey.length > 10) {
    const prompt = `Analyze this text for OCEAN personality traits. Return ONLY JSON: {"O":float,"C":float,"E":float,"A":float,"N":float} (each -1.0 to 1.0).\nText: "${userText.slice(0,500)}"`;
    const resp = await fetch(apiUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: JSON.stringify({ model, messages: [{role:'user',content:prompt}], temperature:0.3, max_tokens:100 })
    });
    if (resp.ok) {
      const body = await resp.json();
      const raw = body.choices?.[0]?.message?.content || '';
      const m = raw.match(/\{[^}]+\}/);
      if (m) {
        const p = JSON.parse(m[0]);
        if (typeof p.O === 'number') {
          ocean = { O:clamp(p.O,-1,1), C:clamp(p.C||0,-1,1), E:clamp(p.E||0,-1,1), A:clamp(p.A||0,-1,1), N:clamp(p.N||0,-1,1) };
          confidence = { O:0.7, C:0.7, E:0.7, A:0.7, N:0.7 };
          apiStatus = 'nvidia'; formatUsed = 'api';
        }
      }
    } else { apiError = `API ${resp.status}`; }
  }
} catch(e) { apiError = e.message; }

if (!ocean) {
  ocean = heuristicOcean(userText);
  confidence = { O:0.45, C:0.45, E:0.45, A:0.45, N:0.45 };
}

const ema = applyEma(ocean, confidence);

return [{ json: {
  ...d,
  detector: {
    api_status: apiStatus, error: apiError, format_used: formatUsed,
    ocean_detected: ocean, smoothed_ocean: ema.smoothedOcean,
    current_confidence: confidence, smoothed_confidence: ema.smoothedConfidence,
    personality_stable: ema.personalityStable, ema_applied: true, ema_alpha: 0.3,
    stabilization_turns: STABILITY_TURNS, turn_number: turnIndex, timestamp: new Date().toISOString()
  },
  previous_state: {
    ...(d.previous_state || {}),
    ocean_history: ema.oceanHistory
  },
  ocean_disc: ema.smoothedOcean
}}];

// ── STEP 4: ZURICH REGULATION (directive mapping + mode routing) ──
const d = $input.first().json;
const det = d.detector || {};
const ocean = det.smoothed_ocean || d.ocean_disc || {O:0,C:0,E:0,A:0,N:0};
const conf = det.smoothed_confidence || {};
const stable = det.personality_stable || false;

const MAP = {
  O: { high:'Invite exploration and novelty', low:'Focus on familiar topics; reduce novelty' },
  C: { high:'Provide organized, structured guidance', low:'Keep flexible, relaxed, and spontaneous' },
  E: { high:'Maintain an energetic, sociable tone', low:'Adopt a calm, low-key style with reflective space' },
  A: { high:'Show warmth, empathy, and collaboration', low:'Use a neutral, matter-of-fact stance' },
  N: { high:'Offer extra comfort; acknowledge anxieties', low:'Reassure stability and confidence' }
};

const directives = [];
const details = [];
for (const [t, v] of Object.entries(ocean)) {
  const val = Number(v||0), c = Number(conf[t]||0.5);
  if (Math.abs(val) > 0.15 && c >= 0.35) {
    const dir = val > 0 ? MAP[t]?.high : MAP[t]?.low;
    if (dir) {
      directives.push(stable ? dir : `${dir} (confidence: ${c.toFixed(2)})`);
      details.push({ trait:t, value:val, confidence:c, directive:dir });
    }
  }
}
if (directives.length === 0) {
  directives.push('Be warm, attentive, and supportive');
  directives.push('Ask open-ended questions to understand the user better');
}

const text = String(d.clean_msg || d.user_message || '').toLowerCase();
const score = (keywords) => keywords.reduce((n, k) => n + (text.includes(k) ? 1 : 0), 0);
const scores = {
  policy: score(['benefit','benefits','eligibility','procedure','policy','form','allowance','invalidenversicherung',' iv ','canton']),
  education: score(['how to','steps','plan','routine','practice','technique','guide','learn']),
  emotional: score(['feel','stressed','anxious','overwhelmed','sad','worried','burned out','panic','lonely'])
};

let coachingMode = 'emotional_support';
if (scores.policy > 0 && scores.emotional > 0) coachingMode = 'mixed';
else if (scores.policy >= scores.education && scores.policy >= scores.emotional && scores.policy > 0) coachingMode = 'policy_navigation';
else if (scores.education >= scores.emotional && scores.education > 0) coachingMode = 'practical_education';

const modeConfidence = Number(((Math.max(scores.policy, scores.education, scores.emotional) + 1) /
  (scores.policy + scores.education + scores.emotional + 3)).toFixed(2));

return [{ json: {
  ...d,
  directives,
  turn_text: d.clean_msg || d.user_message || '',
  coaching_mode: coachingMode,
  mode_confidence: modeConfidence,
  mode_scores: scores,
  regulator: {
    raw_directives: directives, zurich_applied: true,
    confidence_weighted: !stable, regulation_status: 'success',
    directive_count: directives.length, mapping_details: details,
    input_ocean: ocean, input_confidence: conf,
    timestamp: new Date().toISOString()
  }
}}];

// ── MERGE RETRIEVAL RESULTS ──
const regulationItems = $('Enhanced Regulation (Implemented)').all();
const regulationData = regulationItems.length > 0 ? regulationItems[0].json : {};

const retrievalItems = $input.all();
const evidence = [];

for (const item of retrievalItems) {
  const j = item.json;
  if (j && j.source_id && j.content) {
    evidence.push(j);
  }
}

return [{
  json: {
    ...regulationData,
    retrieval: {
      active: (regulationData.coaching_mode === 'policy_navigation' || regulationData.coaching_mode === 'mixed'),
      evidence: evidence,
      count: evidence.length,
      timestamp: new Date().toISOString(),
      debug_raw: retrievalItems.map(i => i.json)
    }
  }
}];

// ── STEP 5: GENERATE RESPONSE (directive-aware heuristic + NVIDIA API) ──
const d = $input.first().json;
const text = String(d.turn_text || d.clean_msg || d.user_message || '').trim();
const ocean = d.ocean_disc || {O:0,C:0,E:0,A:0,N:0};
const directives = d.directives || [];
const stable = d.detector?.personality_stable || false;
const evidence = d.retrieval?.evidence || [];

function pick(arr) { return arr[Math.floor(Math.random() * arr.length)]; }

function extractTopics(text) {
  const low = text.toLowerCase();
  const topics = [];
  const map = {
    meditation: /(meditat|mindful|breathing exercise|zen|mantra)/,
    exercise: /(exercise|workout|gym|running|walk|yoga|sport|swim|hik)/,
    sleep: /(sleep|rest|nap|insomnia|tired|exhausted|bed)/,
    work: /(work|job|office|boss|colleague|career|project|deadline)/,
    family: /(family|parent|mother|father|mom|dad|sibling|brother|sister|child|kid)/,
    friends: /(friend|buddy|pal|mate|companion|social)/,
    health: /(health|doctor|hospital|sick|pain|illness|therapy|therapist)/,
    nature: /(nature|garden|park|tree|flower|mountain|beach|ocean|outdoor)/,
    creativity: /(creat|art|music|paint|writ|draw|sing|danc|cook|craft)/,
    learning: /(learn|study|read|book|course|class|school)/,
    gratitude: /(grateful|thankful|appreciate|blessed|gratitude)/,
    calm: /(calm|peace|serene|tranquil|quiet|still|relax)/,
    energy: /(energy|energetic|alive|vibrant|motivated|excited|pumped)/,
    connection: /(connect|bond|relationship|love|close|together|belonging)/
  };
  for (const [t, re] of Object.entries(map)) { if (re.test(low)) topics.push(t); }
  return topics;
}

function applyDirectiveStyle(base, directives, ocean) {
  let r = base;
  const ds = directives.join(' ').toLowerCase();
  const E = Number(ocean.E||0), A = Number(ocean.A||0), N = Number(ocean.N||0);
  const O = Number(ocean.O||0), C = Number(ocean.C||0);

  let mods = 0;
  if (E > 0.4 && (ds.includes('energetic') || ds.includes('sociable'))) {
    const ep = pick(["I love that energy! ","That's so exciting! ","How wonderful! ","What great vibes! ","Yes, absolutely! "]);
    r = ep + r.charAt(0).toUpperCase() + r.slice(1);
  } else if (E < -0.2) {
    const qp = pick(["I hear you. ","Take your time. ","There's no rush here. ","Let's sit with that for a moment. "]);
    if (!r.startsWith('I hear')) r = qp + r;
  }

  if (mods < 2 && A > 0.3 && (ds.includes('warmth') || ds.includes('empathy') || ds.includes('collaboration'))) {
    r = r.replace(/\bI\b(?='d| think| believe| wonder)/g, 'We');
    if (!r.includes('together') && !r.includes('we') && !r.includes('We'))
      r = r.replace(/\?$/, ' — and I want you to know we\'re in this together?');
    mods++;
  }

  if (mods < 2 && N > 0.3 && (ds.includes('comfort') || ds.includes('anxiet'))) {
    if (!r.includes('safe') && !r.includes('okay') && !r.includes('valid')) {
      const cs = pick([" Remember, whatever you're feeling right now is completely valid."," And it's okay to not have all the answers right now."," Your feelings matter, and there's no wrong way to feel about this."," Take a breath — you're doing better than you think."]);
      r += cs;
      mods++;
    }
  }

  if (mods < 2 && N < -0.3 && ds.includes('stability')) {
    if (!r.includes('strong') && !r.includes('resilient'))
      r = r.replace(/\.$/, ' — and your steadiness really shines through.'); mods++;
  }

  if (mods < 2 && O > 0.3 && (ds.includes('exploration') || ds.includes('novelty'))) {
    if (!r.includes('curious') && !r.includes('explore') && !r.includes('perspective')) {
      const os = pick([" What new perspective has this opened up for you?"," I'm curious what else you might discover here."," Have you explored any unexpected angles on this?"]);
      r = r.replace(/\?$/, '.') + os;
    }
  }

  if (mods < 2 && C > 0.3 && (ds.includes('structured') || ds.includes('organized'))) {
    if (!r.includes('step') && !r.includes('plan') && !r.includes('concrete')) {
      const cs = pick([" Shall we break this down into concrete steps?"," Would it help to organize your thoughts around this?"," Let's approach this systematically — what's the first priority?"]);
      r = r.replace(/\?$/, '.') + cs;
    }
  }

  if (E > 0.3 && (ds.includes('energetic') || ds.includes('sociable'))) {
    r = r.replace(/\.\s/g, '! ').replace(/\.$/, '!');
    r = r.replace(/\bgood\b/gi, m => pick(['great','wonderful','fantastic']));
    r = r.replace(/\bnice\b/gi, m => pick(['amazing','lovely','brilliant']));
  }

  if (ds.includes('calm') || ds.includes('low-key') || ds.includes('reflective space')) {
    r = r.replace(/!/g, '.').replace(/!$/,'.');
    if (!r.includes('space') && !r.includes('pause'))
      r += " Take all the space you need.";
  }

  if (A < -0.2 && (ds.includes('neutral') || ds.includes('matter-of-fact'))) {
    r = r.replace(/!\s?/g, '. ').replace(/!$/, '.');
    r = r.replace(/\breally\s/gi, '').replace(/\btruly\s/gi, '').replace(/\bso\s/gi, '');
  }

  return r;
}

function heuristicResponse(text, ocean, directives) {
  if (evidence.length > 0) {
    const titles = evidence.map(e => e.title).join(', ');
    return applyDirectiveStyle(`I found some official information (${titles}). Based on what I see: ${evidence[0].content.slice(0, 150)}... Shall we look at the details together?`, directives, ocean);
  }
  const low = text.toLowerCase();
  const E = Number(ocean.E||0), A = Number(ocean.A||0), N = Number(ocean.N||0), O = Number(ocean.O||0);
  const topics = extractTopics(text);
  const isGreeting = /(^|\s)(hi|hello|hey|how are you|what's up|good morning|good evening)/i.test(low) && text.length < 40;
  const isPositive = /(good|calm|great|happy|better|peace|grateful|appreciate|wonderful|fantastic|awesome|excited|love|enjoy)/i.test(low);
  const isNegative = /(low|sad|overwhelmed|anxious|stressed|tired|worried|afraid|depressed|frustrated|angry|upset|hurt|lonely|terrible|awful)/i.test(low);
  const isQuestion = /\?/.test(text);
  const isReflective = /(think|wonder|reflect|meaning|purpose|life|feel like|sometimes|realize|understand|aware)/i.test(low);
  const isAdvice = /(best way|should|recommend|suggest|how to|tip|advice|help me)/i.test(low);
  const isSharing = text.length > 80;

  if (isGreeting) {
    return applyDirectiveStyle(pick([
      E > 0.3 ? 'Hey there! Great to hear from you! How has your day been going? Anything on your mind you\'d like to chat about?' : A > 0.2 ? 'Hello! It\'s really nice to connect with you. How are you doing today? I\'m here whenever you\'re ready to share.' : 'Hi! Welcome — I\'m glad you\'re here. How are things going for you today?',
      'Hey! Good to see you. What\'s been on your mind lately?',
      E > 0.3 ? 'Hi there! Always nice to connect. What brings you here today?' : 'Hello. I\'m here and listening. What would you like to talk about?'
    ]), directives, ocean);
  }

  if (isAdvice && topics.length > 0) {
    const t = topics[0];
    const topicR = {
      meditation: ['It sounds like you already have great insight — meditation really can be transformative. How long have you been practicing? I\'d love to hear about your experience.', 'You\'re absolutely right that meditation can be incredibly grounding. What type resonates most with you — guided, breath-focused, or something else?', 'That\'s a wonderful practice. Meditation has such deep benefits for both mind and body. Do you have a regular routine, or is it more spontaneous?'],
      exercise: ['Movement really is such a powerful way to shift your energy. What kind of exercise do you find most enjoyable?', 'You\'re onto something important — physical activity can be one of the best things for our wellbeing. What type works best for you?'],
      sleep: ['Rest is so fundamental to how we feel and function. What\'s your relationship with sleep been like recently?', 'Good sleep really is the foundation of wellbeing. What does your wind-down routine look like?'],
      nature: ['Being in nature really does have a special way of grounding us. What kinds of natural settings do you find most restorative?', 'There\'s something deeply healing about connecting with the natural world. Do you get to spend time outdoors regularly?']
    };
    return applyDirectiveStyle(pick(topicR[t] || [`That's a really insightful perspective on ${t}. What made you realize this?`, `You seem to have a thoughtful approach to ${t}. How has it shaped your daily life?`]), directives, ocean);
  }

  if (isNegative) {
    const emp = pick([`I hear you, and it takes real courage to share when things feel heavy.`, `Thank you for being open about how you're feeling — that truly matters.`, `I can sense this is weighing on you, and I want you to know your feelings are completely valid.`, `It sounds like you're carrying a lot right now. I'm here to listen.`]);
    const sup = N < -0.2 ? pick([`You don't have to navigate this alone.`, `Whatever you're going through, we can face it together at your pace.`, `Sometimes just having someone to listen can make things feel lighter.`]) : pick([`Let's take this one step at a time together.`, `I'm here to support you through this.`, `We can work through this — there's no rush.`]);
    const fol = topics.length > 0 ? pick([`Can you tell me more about how ${topics[0]} has been affecting you?`, `What aspect of ${topics[0]} has been the most challenging?`]) : pick([`Can you tell me more about what's been weighing on you?`, `What feels like the heaviest part of what you're experiencing?`, `When did you first start feeling this way?`]);
    return applyDirectiveStyle(`${emp} ${sup} ${fol}`, directives, ocean);
  }

  if (isPositive) {
    if (topics.length > 0) {
      const tR = {
        calm: ['There\'s something really beautiful about finding that inner calm. It\'s not always easy to get there, so the fact that you\'re feeling it is worth celebrating. What\'s been helping you cultivate that sense of peace?', 'Feeling calm is such a gift to yourself. Is this a feeling you\'ve been actively working toward, or did it come naturally today?', 'That sense of calm sounds really grounding. What does it feel like in your body when you notice that stillness?'],
        meditation: ['It sounds like your meditation practice is really paying off! That calm energy you\'re describing is exactly what consistent practice can bring. How has your practice evolved over time?', 'The peace that comes from meditation is so unique — like a calm from within rather than from circumstances. What drew you to meditation initially?'],
        gratitude: ['That spirit of gratitude you\'re expressing is really powerful. What are you most grateful for today?', 'I love that you\'re in a space of appreciation right now. What\'s been standing out to you lately?'],
        energy: ['I can really feel that energy coming through! There\'s something contagious about that kind of vitality. What\'s been fueling it?', 'That vibrant energy is wonderful. What\'s been driving that motivation?'],
        connection: ['Those deep connections really are what make life rich. What\'s been the most meaningful connection for you recently?', 'The desire for meaningful connection is so important. What kind of connections nourish you most?']
      };
      if (tR[topics[0]]) return applyDirectiveStyle(pick(tR[topics[0]]), directives, ocean);
    }
    return applyDirectiveStyle(pick([`That's really wonderful to hear! What's been the highlight of this positive energy for you?`, `I can sense that good energy in what you're sharing! What do you think is contributing most to this feeling?`, `It sounds like you're in a really good headspace. Those moments are worth savoring. Is there something specific that shifted things for you?`, `What a great place to be in! I'm curious about what's been different lately.`, `That positivity really comes through in your words. What would you say has been the biggest factor?`]), directives, ocean);
  }

  if (isSharing) {
    return applyDirectiveStyle(pick([`Thank you for sharing all of that — I can tell this is something you've been thinking deeply about.${topics.length > 0 ? ` The way you describe ${topics[0]} really resonates.` : ''} What feels most important to you in all of this?`, `I really appreciate you opening up. There's a lot of depth in what you're saying.${topics.length > 0 ? ` I'm particularly struck by what you said about ${topics[0]}.` : ''} What part would you like to explore further?`]), directives, ocean);
  }

  if (isReflective) {
    return applyDirectiveStyle(pick([`Those are really thoughtful reflections. That kind of self-awareness is genuinely valuable.${topics.length > 0 ? ` What specifically about ${topics[0]} has been on your mind?` : ' What drew you to think about this?'}`, `I love that you're sitting with these deeper questions. What has this reflection been revealing to you?`, `There's something really meaningful about taking the time to reflect like this. What insights have been coming up for you?`]), directives, ocean);
  }

  if (isQuestion) {
    return applyDirectiveStyle(pick([`That's a really thoughtful question.${topics.length > 0 ? ` When it comes to ${topics[0]}, ` : ' '}What's your own intuition telling you?`, `Great question! I'd love to explore that with you. What's been prompting you to think about this?`, `I appreciate you asking that. What's your gut feeling on it?`]), directives, ocean);
  }

  return applyDirectiveStyle(pick([`Thanks for sharing that.${topics.length > 0 ? ` I'd like to hear more about your experience with ${topics[0]}.` : ''} What feels most important to talk about right now?`, `I appreciate you opening up.${topics.length > 0 ? ` ${topics[0].charAt(0).toUpperCase()+topics[0].slice(1)} sounds meaningful to you.` : ''} Tell me more.`, `That's interesting — I'd like to understand more.${topics.length > 0 ? ` How has ${topics[0]} been part of your experience?` : ' What would be most helpful to explore together?'}`, `I hear you. What you're sharing matters.${topics.length > 0 ? ` Let's talk more about ${topics[0]} — ` : ' '}What aspect would you like to dive deeper into?`]), directives, ocean);
}

let reply = '', genStatus = 'heuristic', genError = null;

try {
  const apiKey = process.env.NVIDIA_API_KEY || '';
  const apiUrl = process.env.NVIDIA_API_URL || 'https://integrate.api.nvidia.com/v1/chat/completions';
  const model = process.env.NVIDIA_MODEL || 'google/gemma-3-12b-it';

  if (apiKey && apiKey.length > 10) {
    let contextBlock = "";
    if (evidence.length > 0) {
      contextBlock = "\n\nOFFICIAL POLICY CONTEXT (Use this to answer):\n" + evidence.map((e, i) => "[Source " + (i+1) + "]: " + e.title + " - " + e.content).join("\n") + "\n\nINSTRUCTIONS: Answer the user's question using ONLY the provided context. If the answer is not in the context, say you don't know. Do not hallucinate rules.";
    }

    const sysPrompt = `You are CareLoop, a supportive, personality-aware caregiver assistant.\n\nStyle directives:\n${contextBlock}${directives.map((x,i)=>`${i+1}. ${x}`).join('\n')}\n\nRules: 2-4 sentences, reference what the user said, be genuine, ask one follow-up question, never start with 'I appreciate you sharing'.`;
    const resp = await fetch(apiUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: JSON.stringify({ model, messages: [{role:'system',content:sysPrompt},{role:'user',content:text}], temperature: stable ? 0.6 : 0.7, max_tokens: 200 })
    });
    if (resp.ok) {
      const body = await resp.json();
      const c = body.choices?.[0]?.message?.content;
      if (c && c.length > 10) { reply = c; genStatus = 'nvidia'; }
    } else { genError = `API ${resp.status}`; }
  }
} catch(e) { genError = e.message; }

if (!reply) reply = heuristicResponse(text, ocean, directives);

return [{ json: {
  ...d,
  reply: reply,
  generator: {
    raw_content: reply, api_status: genStatus, error: genError,
    format_used: genStatus === 'nvidia' ? 'api' : 'heuristic-fallback',
    directives_applied: directives, personality_stable: stable,
    user_input: text, generation_config: { temperature: stable ? 0.6 : 0.7, max_tokens: 200, model: process.env.NVIDIA_MODEL || 'google/gemma-3-12b-it' },
    ready_for_verification: true, topics_detected: extractTopics(text),
    timestamp: new Date().toISOString()
  },
  choices: [{ message: { content: reply } }]
}}];

// ── STEP 5b: GROUNDING VERIFIER (claim-to-evidence mapping) ──
// Per Spec §7.3, §8.4.I: every policy claim must map to ≥1 evidence chunk

const d = $input.first()?.json || {};
const mode = String(d.coaching_mode || 'emotional_support');
const isPolicyMode = mode === 'policy_navigation' || mode === 'mixed';
const evidence = Array.isArray(d.retrieval?.evidence) ? d.retrieval.evidence : [];
const draft = String(d.generator?.raw_content || d.reply || '').trim();

// Policy claim patterns to detect
const POLICY_PATTERNS = [
  /you (?:are|may be|might be|could be) (?:eligible|entitled|qualified)/gi,
  /the (?:benefit|allowance|payment|grant|subsidy) (?:is|amounts? to|equals?)/gi,
  /you (?:can|may|must|should|need to) (?:apply|submit|register|file)/gi,
  /(?:IV|AHV|EL|Invalidenversicherung)\s+(?:provides?|covers?|pays?|offers?)/gi,
  /according to (?:federal|cantonal|swiss) (?:law|regulation|policy)/gi,
  /the (?:deadline|requirement|condition|criteria) (?:is|are)/gi,
  /(?:federal|cantonal) (?:benefits?|support|assistance) (?:include|cover|provide)/gi,
  /(?:CHF|Fr\.)\s*[\d,.']+/gi,
  /\d+\s*(?:days?|weeks?|months?)\s+(?:processing|waiting|review)/gi,
  /forms?\s+(?:must|should|need to)\s+be\s+(?:submitted|filed|sent)/gi
];

function extractClaims(text) {
  const claims = [];
  const seen = new Set();
  for (const pattern of POLICY_PATTERNS) {
    const matches = text.match(pattern) || [];
    for (const m of matches) {
      const normalized = m.toLowerCase().trim();
      if (!seen.has(normalized)) {
        seen.add(normalized);
        claims.push({ text: m, pattern: pattern.source.slice(0, 40) });
      }
    }
  }
  return claims;
}

function isGrounded(claim, evidenceList) {
  if (!evidenceList.length) return { grounded: false, source: null };
  const claimLow = claim.text.toLowerCase();
  const claimWords = claimLow.split(/\s+/).filter(w => w.length > 3);

  for (const ev of evidenceList) {
    const evContent = String(ev.content || '').toLowerCase();
    const evTitle = String(ev.title || '').toLowerCase();
    const combined = evContent + ' ' + evTitle;

    const matchCount = claimWords.filter(w => combined.includes(w)).length;
    const matchRatio = claimWords.length > 0 ? matchCount / claimWords.length : 0;

    const chfMatch = claim.text.match(/CHF\s*[\d,.']+/i);
    const pctMatch = claim.text.match(/\d+\s*%/);
    if (chfMatch && combined.includes(chfMatch[0].toLowerCase())) {
      return { grounded: true, source: ev.source_id, matchType: 'amount_exact' };
    }
    if (pctMatch && combined.includes(pctMatch[0])) {
      return { grounded: true, source: ev.source_id, matchType: 'percentage_exact' };
    }

    if (matchRatio >= 0.4) {
      return { grounded: true, source: ev.source_id, matchType: 'keyword_overlap', matchRatio };
    }
  }
  return { grounded: false, source: null };
}

let groundingStatus = 'skipped';
let groundingScore = 1.0;
const claimMappings = [];
const ungroundedClaims = [];
let modifiedDraft = draft;

if (isPolicyMode) {
  const extractedClaims = extractClaims(draft);

  if (extractedClaims.length === 0 && evidence.length > 0) {
    groundingStatus = 'ok';
  } else if (extractedClaims.length > 0 && evidence.length === 0) {
    groundingStatus = 'failed';
    groundingScore = 0.0;
    ungroundedClaims.push(...extractedClaims.map(c => c.text));
    modifiedDraft = "I want to help with your policy question, but I need to verify the official information first. Could you tell me your canton and the specific benefit you're asking about? I'll make sure to provide you with accurate, sourced information.";
  } else if (extractedClaims.length > 0 && evidence.length > 0) {
    let groundedCount = 0;
    for (const claim of extractedClaims) {
      const result = isGrounded(claim, evidence);
      claimMappings.push({
        claim: claim.text,
        grounded: result.grounded,
        source: result.source,
        matchType: result.matchType || null
      });
      if (result.grounded) {
        groundedCount++;
      } else {
        ungroundedClaims.push(claim.text);
      }
    }

    const groundingRatio = groundedCount / extractedClaims.length;
    groundingScore = groundingRatio;

    if (groundingRatio >= 0.8) {
      groundingStatus = 'ok';
    } else if (groundingRatio >= 0.5) {
      groundingStatus = 'degraded';
      for (const uc of ungroundedClaims) {
        const escaped = uc.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        modifiedDraft = modifiedDraft.replace(new RegExp(escaped, 'gi'), '[information pending verification]');
      }
    } else {
      groundingStatus = 'failed';
      modifiedDraft = "I found some policy information, but I want to make sure I give you accurate details. Based on what I can verify: " + evidence.slice(0, 2).map(e => e.title).join(' and ') + ". Could you help me narrow down your specific question so I can provide properly sourced guidance?";
    }
  } else {
    groundingStatus = 'ok';
  }
} else {
  const accidentalClaims = extractClaims(draft);
  if (accidentalClaims.length > 0) {
    groundingStatus = 'warning';
    groundingScore = 0.7;
    for (const ac of accidentalClaims) {
      claimMappings.push({ claim: ac.text, grounded: false, source: null, warning: 'policy_claim_in_non_policy_mode' });
    }
  }
}

return [{ json: {
  ...d,
  reply: modifiedDraft,
  grounding_verifier: {
    status: groundingStatus,
    score: Number(groundingScore.toFixed(2)),
    claims_detected: claimMappings.length,
    claims_grounded: claimMappings.filter(c => c.grounded).length,
    claims_ungrounded: ungroundedClaims.length,
    claim_mappings: claimMappings,
    ungrounded_claims: ungroundedClaims,
    evidence_count: evidence.length,
    evidence_sources: evidence.map(e => e.source_id),
    mode: mode,
    is_policy_mode: isPolicyMode,
    timestamp: new Date().toISOString()
  }
}}];

// ── STEP 6: VERIFICATION (blocking safety gate) ──
const d = $input.first()?.json || {};
const rawDraft = d.reply || d.generator?.raw_content || d.choices?.[0]?.message?.content || '';
const draft = String(rawDraft || '').trim();
const groundingResult = d.grounding_verifier || {};

const issues = [];
let score = 1.0;

// Integrate grounding verifier results
if (groundingResult.status === 'failed') {
  issues.push(`Grounding failed: ${groundingResult.claims_ungrounded} ungrounded policy claims`);
  score -= 0.5;
} else if (groundingResult.status === 'degraded') {
  issues.push(`Grounding degraded: ${groundingResult.claims_ungrounded} claims replaced`);
  score -= 0.2;
} else if (groundingResult.status === 'warning') {
  issues.push('Warning: policy claims detected in non-policy mode');
  score -= 0.1;
}

const bannedClaims = ['research shows','studies indicate','experts say','science shows','data suggests'];
const qCount = (draft.match(/\?/g) || []).length;
const wCount = draft ? draft.split(/\s+/).length : 0;
const hasSessionId = typeof d.session_id === 'string' && d.session_id.length > 0;
const hasMode = ['emotional_support', 'practical_education', 'policy_navigation', 'mixed'].includes(String(d.coaching_mode || ''));

if (!hasSessionId) { issues.push('Missing session_id'); score -= 0.4; }
if (!hasMode) { issues.push('Invalid coaching_mode'); score -= 0.3; }
if (!draft) { issues.push('Empty assistant draft'); score -= 0.5; }
if (qCount > 2) { issues.push(`Too many questions (${qCount})`); score -= 0.1; }
if (wCount > 0 && (wCount < 12 || wCount > 220)) { issues.push(`Word count ${wCount} outside range`); score -= 0.15; }
for (const c of bannedClaims) {
  if (draft.toLowerCase().includes(c)) {
    issues.push(`Unsupported claim phrase: "${c}"`);
    score -= 0.2;
  }
}

let verificationStatus = 'ok';
let finalReply = draft;

if (!draft || score < 0.5 || issues.some((x) => x.includes('Missing session_id') || x.includes('Invalid coaching_mode'))) {
  verificationStatus = 'failed';
  finalReply = "I want to support you safely. Could you share one specific concern right now so I can give structured next steps?";
} else if (issues.length > 0 && score < 0.8) {
  verificationStatus = 'degraded';
  finalReply = draft.replace(/research shows|studies indicate|experts say|science shows|data suggests/gi, 'from what is known');
} else if (issues.length > 0) {
  verificationStatus = 'passed_with_warnings';
}

return [{ json: {
  ...d,
  reply: finalReply,
  choices: [{ message: { content: finalReply } }],
  verifier: {
    verification_status: verificationStatus,
    adherence_score: Math.max(0, Number(score.toFixed(2))),
    issues_identified: issues,
    blocked: verificationStatus === 'failed',
    verified_response: finalReply,
    original_response: rawDraft,
    grounding_integrated: true,
    grounding_status: groundingResult.status || 'skipped',
    grounding_score: groundingResult.score || null,
    timestamp: new Date().toISOString()
  }
}}];

// ── STEP 7: FORMAT FINAL RESPONSE for webhook ──
const d = $input.first().json;

const mode = d.coaching_mode || 'emotional_support';
const isPolicyMode = mode === 'policy_navigation' || mode === 'mixed';
const retrievalEvidence = Array.isArray(d.retrieval?.evidence) ? d.retrieval.evidence : [];
const hasEvidence = retrievalEvidence.length > 0;
const groundingResult = d.grounding_verifier || {};

let content = d.reply || d.verifier?.verified_response || d.generator?.raw_content || 'How can I help you today?';
if (isPolicyMode && !hasEvidence) {
  const fallbackPolicy = "I can help with policy navigation, but I do not have verified source evidence right now. I can provide general guidance first, and we should confirm details with official cantonal or federal sources. Could you share your canton and exact benefit question?";
  content = mode === 'mixed' ? `${content}\n\n${fallbackPolicy}` : fallbackPolicy;
}

const citations = hasEvidence
  ? retrievalEvidence.map((e) => ({
      source_id: e.source_id || 'unknown_source',
      title: e.title || 'Untitled source',
      url: e.url || ''
    }))
  : [];

const retrievalStatus = isPolicyMode ? (hasEvidence ? 'ok' : 'degraded') : 'skipped';

return [{ json: {
  session_id: d.session_id || '',
  message: {
    role: 'assistant',
    content,
    timestamp: new Date().toISOString()
  },
  personality_state: {
    ocean: d.detector?.smoothed_ocean || d.ocean_disc || {O:0,C:0,E:0,A:0,N:0},
    stable: d.detector?.personality_stable || false,
    confidence: d.detector?.smoothed_confidence || {},
    ema_applied: d.detector?.ema_applied || false
  },
  policy_navigation: {
    active: isPolicyMode,
    citations,
    grounding: {
      status: groundingResult.status || 'skipped',
      score: groundingResult.score || null,
      claims_detected: groundingResult.claims_detected || 0,
      claims_grounded: groundingResult.claims_grounded || 0
    }
  },
  regulation: {
    directives: d.directives || [],
    zurich_applied: d.regulator?.zurich_applied || false
  },
  pipeline_status: {
    detector: d.detector?.api_status || 'unknown',
    generator: d.generator?.api_status || 'unknown',
    verifier: d.verifier?.verification_status || 'unknown',
    retrieval: retrievalStatus,
    grounding: groundingResult.status || 'skipped',
    fact_invariance_check: isPolicyMode ? (groundingResult.status === 'ok' ? 'pass' : groundingResult.status === 'degraded' ? 'partial' : 'fail') : 'skipped'
  },
  debug: {
    detection_error: d.detector?.error || null,
    generation_error: d.generator?.error || null,
    topics_detected: d.generator?.topics_detected || [],
    turn_index: d.turn_index || 1,
    mode_scores: d.mode_scores || null,
    retrieval_evidence_count: retrievalEvidence.length,
    grounding_claim_mappings: groundingResult.claim_mappings || [],
    retrieval_debug: d.retrieval?.debug_raw || null
  },
  coaching_mode: mode,
  mode_confidence: d.mode_confidence ?? null
}}];

// ── DB PREP: Ensure valid UUID before saves ──
const d = $input.first().json;
const raw = String(d.session_id || '').trim();
const re = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
function uuidV4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}
return [{ json: { ...d, safe_session_id: re.test(raw) ? raw : uuidV4() } }];
